#include<bits/stdc++.h>
using namespace std;
char sa[505],sb[505];

int main()
{

	int len,s=0;
	double n;
	scanf("%lf",&n);
	scanf("%s",sa);
	scanf("%s",sb);
	len=strlen(sa);
	//len=strlen(sb);
	for(int i=0;i<=len-1;i++)
	{
		if(sa[i]==sb[i])
		{
			s++;
		}
	}
	if(1.0*s/len>=n)
	{
		printf("yes");
	}
	else
	{
		printf("no");
	}
	return 0;
}
